/**
 * @name Button
 * @description Highly customizable button component with multiple variants.
 * @category General
 */

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow-xs ring-1 ring-white/60 duration-600 ease-inOut hover:bg-primary/95 ",
        destructive:
          "bg-destructive text-white shadow-[inset_0_.2px_.2px_red,0_1px_2px_2px_#00000030,0_2px_2px_#00000015] hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border bg-background shadow-[inset_0_.5px_.5px_#ffffff30,0_1px_2px_2px_#00000030,0_2px_2px_#00000015] hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        primary:
          "bg-secondary text-secondary-foreground shadow-[inset_0_.5px_.5px_#ffffff30,0_1px_2px_2px_#00000030,0_2px_2px_#00000015] hover:bg-secondary/80",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        sm: "h-8 rounded-md gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-8 rounded-full",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot : "button"

  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }), "overflow-hidden")}
      {...props}
    />
  )
}

export { Button, buttonVariants }

import { motion } from "motion/react"

interface BadgesubItems {
    title: string,
    desc: string
}
interface BadgeProps {
    data: BadgesubItems[]
}

const Badge = ({ data }: BadgeProps) => {
    return (
        <>
            {data.map((card: BadgesubItems, idx: number) => (
                <motion.div
                    whileHover={{ y: -4 }}
                    key={idx}
                    className="p-5 rounded-2xl bg-neutral-50 dark:bg-white/5 border border-neutral-200 dark:border-white/10 hover:border-neutral-300 dark:hover:border-white/20 transition-all cursor-pointer"
                >
                    <h4 className="text-[10px] font-bold text-neutral-500 dark:text-neutral-400 uppercase tracking-widest mb-3">{card.title}</h4>
                    <p className="text-sm font-medium text-neutral-700 dark:text-neutral-300">{card.desc}</p>
                </motion.div>
            ))}
        </>
    )
}
export default Badge;

import { ArrowUp, DollarSign, Globe, TrendingUp, Zap } from "lucide-react";
import { cn } from "@/lib/utils";

interface cardDetails {
  title: string;
  value: string;
  trend: string;
  positive: boolean;
  icon: React.ReactNode;
  background?: string;
}

const carddata: cardDetails[] = [
  { title: "Last 30 Days", value: "€12,220.64", trend: "+22.2%", positive: true, icon: <DollarSign size={16} className="text-green-500" />, background: "bg-neutral-50/50" },
]


const Card = () => {
  return (
    <div className="w-1/2 gap-2">
      {carddata.map((kpi) => (
        <div key={kpi.title} className="group relative shadow-md rounded border border-[var(--border-color)] p-2 overflow-hidden bg-[var(--card-bg)] transition-all duration-300">
          <div className={cn(
            "absolute top-0 left-0 w-2.5 h-2.5 border-t-2 border-l-2 transition-all duration-300 rounded-tl",
            kpi.positive ? "border-neutral-500/50" : "border-red-500"
          )} />
          <div className={cn(
            "absolute top-0 right-0 w-2.5 h-2.5 border-t-2 border-r-2 transition-all duration-300 rounded-tr",
            kpi.positive ? "border-neutral-500/50" : "border-red-500"
          )} />
          <div className={cn(
            "absolute bottom-0 left-0 w-2.5 h-2.5 border-b-2 border-l-2 transition-all duration-300 rounded-bl",
            kpi.positive ? "border-neutral-500/50" : "border-red-500"
          )} />
          <div className={cn(
            "absolute bottom-0 right-0 w-2.5 h-2.5 border-b-2 border-r-2 transition-all duration-300 rounded-br",
            kpi.positive ? "border-neutral-500/50" : "border-red-500"
          )} />
          <div className="flex items-center justify-between mb-4">
            <span className="text-[10px] font-bold uppercase tracking-widest leading-none text-[var(--text-secondary)]">{kpi.title}</span>
            <span className={cn(
              "p-1 rounded-sm border flex items-center justify-center",
              kpi.background ? kpi.background : "bg-neutral-300/20 border-[var(--border-color)]"
            )}>
              {kpi.icon}
            </span>
          </div>
          <div className="flex flex-col gap-1">
            <span className="text-2xl font-semibold tracking-tight text-[var(--text-primary)]">{kpi.value}</span>
            <div className="flex items-center gap-2 mt-2">
              <span className={cn(
                "text-[10px] font-bold px-1.5 py-0.5 flex items-center gap-0.5 rounded",
                kpi.positive ? "bg-green-500 text-white" : "bg-red-500 text-white"
              )}>
                {kpi.positive ? <ArrowUp size={8} strokeWidth={3} /> : <ArrowUp size={8} strokeWidth={3} className="rotate-180" />}
                {kpi.trend}
              </span>
            </div>
          </div>
        </div>
      ))}
    </div>
  )
}

export default Card

import React from "react";
import { motion } from "framer-motion";
import { X } from "lucide-react";

interface FilterChipProps {
    filterOptions: {
        group: string;
        key: string;
        options: { label: string; value: string }[];
    }[];
    filters: Record<string, string[]>;
    removeValue: (groupKey: string, value: string) => void;
}

export const FilterChip = ({ filterOptions, filters, removeValue }: FilterChipProps) => {
    return (
        <div className="flex gap-2 overflow-x-auto overflow-hidden">
            {filterOptions.map(group =>
                filters[group.key].map((val) => {
                    const opt = group.options.find((o: any) => o.value === val);
                    return (
                        <motion.div
                            key={`${String(group.key)}-${val}`}
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.8 }}
                            className="flex items-center gap-2 bg-white text-blue-700 px-3 py-1 rounded-full text-[11px] font-medium "
                        >
                            <span className="text-slate-400 font-normal">{group.group}:</span>
                            <span>{opt?.label || val}</span>
                            <button
                                onClick={() => removeValue(group.key, val)}
                                className="text-red-500 cursor-pointer"
                            >
                                <X size={12} />
                            </button>
                        </motion.div>
                    );
                })
            )}
        </div>
    );
};

import React, { useEffect, useState } from 'react'
import Header from './Header';
import { Link, useSearchParams } from 'react-router-dom';
import Upgradefilter from './MultipleFilter';
import PaginationControls from './Pagination';
import Skeleton from './Skeleton';
import { RotateCcw, X } from 'lucide-react';
import { FilterChip } from './Filterchip';

interface FiltersState {
    details: string[];
    version: string[];
    cloud: string[];
    [key: string]: string[];
}

interface Cluster {
    id: string | number;
    name: string;
    status: string;
    current_version: string;
    provider: string;
    lifecycle?: {
        status?: string;
        end_of_standard_support?: string;
    };
    prevbuilds?: Array<{
        id?: string;
        date?: string;
        status?: string;
    }>;
}


export const Upgradecluster = () => {
    const [accounts, setAccounts] = useState<Cluster[]>([]);
    const [filteredData, setFilteredData] = useState<Cluster[]>([]);
    const [selectedAccount, setSelectedAccount] = useState("");
    const [loading, setLoading] = useState(false);
    const [filters, setFilters] = useState<FiltersState>({
        details: [],
        version: [],
        cloud: [],
    });
    const [expandedId, setExpandedId] = useState(null);
    const [searchParams] = useSearchParams();
    const [currentPage, setCurrentPage] = useState(1);

    const accountIdParam = searchParams.get("account_id");
    const rowsPerPage = 10;

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            // try {
            //     const data = await apiRequest(API_ENDPOINTS.getEKSClusters, "GET");
            //     const accountsArray = Array.isArray(data) ? data : [];

            //     setAccounts(accountsArray);

            //     if (accountIdParam) {
            //         setSelectedAccount(accountIdParam);
            //         const filtered = accountsArray.filter(
            //             (c) => String(c.id) === String(accountIdParam)
            //         );
            //         setFilteredData(filtered);
            //     } else {
            //         setFilteredData(accountsArray);
            //     }
            // } catch (error) {
            //     console.error("Error fetching clusters:", error);
            //     setAccounts([]);
            //     setFilteredData([]);
            //     setCurrentPage(1);
            // } finally {
            //     setLoading(false);
            // }
        };

        fetchData();
    }, [accountIdParam]);

    useEffect(() => {
        let filtered = [...accounts];

        if (filters.details.length > 0) {
            filtered = filtered.filter((item) =>
                item.lifecycle?.status && filters.details?.includes(item.lifecycle?.status?.toLowerCase())
            );
        }
        if (filters.version.length > 0) {
            filtered = filtered.filter((item) =>
                item.current_version && filters.version?.includes(item.current_version?.toLowerCase())
            );
        }
        if (filters.cloud.length > 0) {
            filtered = filtered.filter((item) =>
                item.provider && filters.cloud?.includes(item.provider?.toLowerCase())
            );
        }
        setFilteredData(filtered);
        setCurrentPage(1);
    }, [filters, accounts]);

    const handleReset = () => {
        setFilters({
            details: [],
            version: [],
            cloud: [],
        });
        setSelectedAccount("");
        setFilteredData(accounts);
        setCurrentPage(1);
    };


    const totalPages = Math.ceil(filteredData.length / rowsPerPage);
    const paginatedData = filteredData.slice(
        (currentPage - 1) * rowsPerPage,
        currentPage * rowsPerPage
    );



    const filterOptions = React.useMemo(() => {
        const uniqueDetails = [...new Set(accounts.map(item => item?.lifecycle?.status?.toLowerCase()).filter(Boolean))];
        const uniqueVersions = [...new Set(accounts.map(item => item?.current_version?.toLowerCase()).filter(Boolean))];
        const uniqueClouds = [...new Set(accounts.map(item => item?.provider?.toLowerCase()).filter(Boolean))];

        return [
            {
                group: "Details",
                key: "details",
                //  method for fetching data from api

                // options: uniqueDetails.map((status: any) => ({
                //     label: status.charAt(0).toUpperCase() + status.slice(1) || "N/A",
                //     value: status
                // }))

                // dummy data
                options: [
                    { label: "Active", value: "active" },
                    { label: "Inactive", value: "inactive" },
                    { label: "Pending", value: "pending" },
                    { label: "Unknown", value: "unknown" },
                ]

            },
            {
                group: "Version",
                key: "version",
                // method for fetching data from api
                
                // options: uniqueVersions.map(version => ({
                //     label: `v${version}`,
                //     value: version
                // }))

                // dummy data
                options: [
                    { label: "v1.35", value: "v1.35" },
                    { label: "v1.34", value: "v1.34" },
                    { label: "v1.33", value: "v1.33" },
                    { label: "v1.32", value: "v1.32" },
                ]
            },
            {
                group: "Cloud",
                key: "cloud",
                
                // method for fetching data from api
                
                // options: uniqueClouds.map(cloud => ({
                //     label: cloud.toUpperCase(),
                //     value: cloud
                // }))

                options: [
                    { label: "AWS", value: "aws" },
                    { label: "GCP", value: "gcp" },
                    { label: "Azure", value: "azure" },
                ]
            }
        ];
    }, [accounts]);



    const removeValue = (groupKey: string, value: string) => {
        setFilters(prev => ({
            ...prev,
            [groupKey]: prev[groupKey].filter((v: any) => v !== value)
        }));
    };

    return (
        <section className="h-full w-full">
            <div className="p-5 pt-0">
                <div className="space-y-4 mt-3">
                    <div className="flex justify-between items-center gap-3">
                        <div className=" ring-1 ring-slate-200 rounded-md w-1/2 p-2 h-10">
                            <FilterChip
                                filterOptions={filterOptions}
                                filters={filters}
                                removeValue={removeValue}
                            />
                        </div>
                        <div className="flex gap-3 items-center justify-start md:justify-end ">
                            <Upgradefilter
                                filterOptions={filterOptions}
                                defaultLabel="Select Filters"
                                filters={filters}
                                onFilterChange={setFilters}
                            />
                            <button
                                className="group flex items-center gap-2 px-4 py-1.5 bg-white/50 hover:bg-white/80 backdrop-blur-sm text-slate-600 rounded-lg text-sm font-medium transition-all shadow-sm border border-white/40 cursor-pointer"
                                onClick={handleReset}
                            >
                                <RotateCcw size={14} />
                                Reset
                            </button>
                        </div>
                    </div>

                    <div className='w-full h-[calc(100vh-200px)] bg-white rounded-xl border border-slate-200 overflow-hidden'>
                        {loading ? (
                            [...Array(5)].map((_, index) => (
                                <div key={`skeleton-${index}`} className="w-full p-4 border-b border-slate-100 animate-pulse">
                                    <div className="bg-neutral-50 p-3 rounded-md space-y-3">
                                        <div className="flex justify-between items-start">
                                            <Skeleton variant="rectangular" width="40%" height={20} className="rounded" />
                                            <Skeleton variant="rectangular" width="60px" height={20} className="rounded-full" />
                                        </div>
                                        <div className="flex justify-between items-center">
                                            <Skeleton variant="text" width="30%" height={16} />
                                            <Skeleton variant="text" width="40%" height={16} />
                                        </div>
                                    </div>
                                </div>
                            ))
                        ) : paginatedData.length > 0 ? (
                            paginatedData.map((items: any, id: number) => (
                                <React.Fragment key={items.id || id}>
                                    <div className='w-full p-4 bg-white transition-colors border-b border-slate-100 last:border-0'>
                                        <div
                                            onClick={() => setExpandedId(String(expandedId) === String(items.id) ? null : items.id)}
                                            className='flex flex-col gap-2 bg-neutral-50 p-3 shadow-sm rounded-md cursor-pointer hover:bg-neutral-100 transition-colors group'
                                        >
                                            <div className='flex justify-between items-start'>
                                                <Link to={`/${items.id}/Upgradehistory`}>
                                                    <h3 className='text-md font-bold text-slate-800 transition-colors'>
                                                        {items.name}
                                                    </h3>
                                                </Link>
                                                <span className={`px-2.5 py-0.5 rounded-full text-[11px] font-bold uppercase border shadow-sm ${items.status?.toLowerCase() === 'active'
                                                    ? 'bg-green-50 text-green-700 border-green-200'
                                                    : 'bg-slate-50 text-slate-700 border-slate-200'
                                                    }`}>
                                                    {items.status}
                                                </span>
                                            </div>
                                            <div className='flex justify-between items-center text-sm text-slate-500'>
                                                <div className='flex items-center gap-2'>
                                                    <span className='font-medium text-slate-400'>Version:</span>
                                                    <span className='px-2 py-0.5 bg-blue-50 text-blue-700 rounded-md font-mono text-xs'>
                                                        {items.current_version || 'N/A'}
                                                    </span>
                                                </div>
                                                <div className='flex items-center gap-2'>
                                                    <span className='font-medium text-slate-400'>Standard Support End:</span>
                                                    <span className='text-slate-700'>
                                                        {items.lifecycle?.end_of_standard_support
                                                            ? new Date(items.lifecycle.end_of_standard_support).toLocaleDateString()
                                                            : "—"}
                                                    </span>
                                                </div>
                                            </div>
                                        </div>
                                        {String(expandedId) === String(items.id) && (
                                            <div className='mt-2 p-4 bg-slate-50 rounded-lg border border-slate-200 animate-in fade-in slide-in-from-top-2'>
                                                <h4 className='text-sm font-semibold text-slate-700 mb-2'>Previous Builds</h4>
                                                {items.prevbuilds && items.prevbuilds.length > 0 ? (
                                                    <div className='space-y-2'>
                                                        {items.prevbuilds.map((build: any, idx:number) => (
                                                            <div key={idx} className='flex justify-between items-center text-xs p-2 bg-white rounded border border-slate-100'>
                                                                <span className='font-mono'>{build.id || `Build #${idx + 1}`}</span>
                                                                <span className='text-slate-500'>{build.date || 'No Date'}</span>
                                                                <span className={`font-bold ${build.status === 'Success' ? 'text-green-600' : 'text-red-500'}`}>
                                                                    {build.status || 'Unknown'}
                                                                </span>
                                                            </div>
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <div className='text-xs text-slate-400 italic'>No previous builds found for this cluster.</div>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                </React.Fragment>
                            ))
                        ) : (
                            <div className='p-10 text-center text-slate-400'>
                                No clusters found matching your criteria.
                            </div>
                        )}
                    </div>
                    <div className="flex justify-end mt-6">
                        <PaginationControls
                            currentPage={currentPage}
                            totalPages={totalPages}
                            onPageChange={setCurrentPage}
                        />
                    </div>
                </div>
            </div>
        </section>
    );
};

import { motion } from "framer-motion";
import React from "react";

interface HeaderProps {
  page: string;
  subPage?: string;
  action?: React.ReactNode;
}

const Header = ({ page, subPage, action }: HeaderProps) => {
  return (
    <motion.header
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      className="relative top-4 z-40 mx-5 mb-6 rounded-lg dark:bg-[var(--bg)] bg-neutral-200 px-6 py-3 flex items-center justify-between"
    >
      {page && (
        <div className='flex flex-col'>
          <h1 className='text-lg font-bold dark:text-white text-slate-800 tracking-tight'>{page}</h1>
          {subPage && <span className='text-xs font-medium dark:text-neutral-400 text-slate-500 mt-0.5'>{subPage}</span>}
        </div>
      )}

      <div className="flex items-center gap-4">
        {action}
      </div>
    </motion.header>
  )
}

export default Header

import React, { useEffect, useRef, useState } from "react";
import { ChevronDown, Check, X } from "lucide-react";
import { cn } from "@/lib/utils";

interface UpgradefilterDetails {
    filterOptions: {
        group: string;
        key: string;
        options: {
            value: string;
            label: string;
        }[];
    }[];
    filters: Record<string, string[]>;
    onFilterChange: (filter: any) => void;
    defaultLabel?: string;
}

const Upgradefilter = ({
    filterOptions,
    filters,
    onFilterChange,
    defaultLabel = "Filter",
}: UpgradefilterDetails) => {
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const totalSelected = Object.values(filters).flat().length;

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current?.contains(e.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () =>
            document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const toggleValue = (groupKey: string, value: string) => {
        onFilterChange((prev: any) => {
            const exists = prev[groupKey].includes(value);
            return {
                ...prev,
                [groupKey]: exists
                    ? prev[groupKey].filter((v: any) => v !== value)
                    : [...prev[groupKey], value],
            };
        });
    };

    return (
        <div className="relative" ref={dropdownRef}>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center justify-between w-45 px-4 py-1.5 text-sm bg-white  backdrop-blur-sm text-black rounded-lg shadow-sm cursor-pointer outline:none select-none"
            >
                <span>{defaultLabel}</span>
                {totalSelected > 0 && (
                    <span className="ml-2 text-xs bg-blue-600 text-white rounded-full px-2">
                        {totalSelected}
                    </span>
                )}
                <ChevronDown
                    className={cn("w-4 h-4 transition-transform", isOpen && "rotate-180")}
                />
            </button>

            {isOpen && (
                <div className="absolute z-50 mt-2 w-65 bg-white rounded-xl shadow-xl cursor-pointer">
                    {filterOptions.map((group) => (
                        <div key={group.key}>
                            <p className="px-4 py-2 text-xs font-semibold text-black">
                                {group.group}
                            </p>
                            {group.options.map((opt) => {
                                const isSelected = filters[group.key].includes(opt.value);
                                return (
                                    <button
                                        key={opt.value}
                                        onClick={() => toggleValue(group.key, opt.value)}
                                        className={cn(
                                            "flex w-full items-center justify-between px-4 py-2 text-sm",
                                            isSelected
                                                ? "bg-blue-50 text-blue-700"
                                                : "hover:bg-slate-50 text-slate-600"
                                        )}
                                    >
                                        {opt.label}
                                        {isSelected && <Check className="w-4 h-4" />}
                                    </button>
                                );
                            })}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Upgradefilter

import React from "react";

interface PaginationDetails {
    currentPage: number;
    totalPages: number;
    onPageChange: (page: number) => void;
}

const PaginationControls = ({ currentPage, totalPages = 6, onPageChange }: PaginationDetails) => {
    if (!totalPages || totalPages <= 0) return null;

    return (
        <div className="flex items-center justify-center py-3 ">
            <button
                disabled={currentPage === 1 || totalPages <= 1}
                onClick={() => onPageChange(currentPage - 1)}
                className={` px-3 py-1 rounded-md cursor-pointer select-none outline-none text-sm ${currentPage === 1 || totalPages <= 1 ? "bg-gray-400 text-white" : "bg-blue-500 text-white shadow-sm"}`}
            >
                Previous
            </button>

            <span className="dark:text-neutral-400 text-gray-600 text-sm mx-4 select-none">
                Page {currentPage} of {totalPages}
            </span>

            <button
                disabled={currentPage === totalPages || totalPages <= 1}
                onClick={() => onPageChange(currentPage + 1)}
                className={` px-4 py-1 rounded-md select-none outline-none text-sm cursor-pointer ${currentPage === totalPages || totalPages <= 1 ? "bg-gray-400 text-white" : "bg-blue-500 text-white shadow-sm"}`}
            >
                Next
            </button>
        </div>
    );
};

export default PaginationControls;

import React from "react"
import { cn } from "@/lib/utils"
import { ScrollArea } from "@workspace/ui/components/ui/scroll-area"
import { motion, AnimatePresence } from "framer-motion"
import { Link, useLocation } from "react-router-dom"
import { PanelLeftClose, PanelRightClose } from "lucide-react";
import { IconFile, IconFolders, IconStarSparkle } from "nucleo-glass"
type CodeThemeName = "default" | "min" | "vitesse" | "slack" | "nord" | "dracula" | "one-dark-pro" | "catppuccin"


interface NavItem {
    title: string
    href?: string
    disabled?: boolean
    external?: boolean
    label?: string
    icon?: React.ReactNode
    items?: NavItem[],
    className?: string,
    pathname?: string,
    setIsOpen?: (open: boolean) => void
}

interface NavItemWithChildren extends NavItem {
    items: NavItemWithChildren[]
}

interface SidebarNavItem extends NavItemWithChildren { }



interface DocsConfig {
    sidebarNav: SidebarNavItem[]
    codeTheme?: CodeThemeName
}

export const docsConfig: DocsConfig = {
    codeTheme: (process.env.CODE_THEME as CodeThemeName) || "nord",
    sidebarNav: [
        {
            title: "Getting Started",
            items: [
                {
                    title: "Introduction",
                    href: "/docs/introduction",
                    items: []
                },
                {
                    title: "Installation",
                    href: "/docs/installation",
                    items: [],
                },
                {
                    title: "Style",
                    href: "/docs/style/style",
                    items: [],
                    icon: <IconStarSparkle size={14} />
                }
            ],
            icon: <IconFile size={16} />
        },
        {
            title: "Components",
            items: [
                {
                    title: "Table",
                    href: "/docs/components/table",
                    items: [],
                },
                {
                    title: "Skeleton",
                    href: "/docs/components/skeleton",
                    items: [],
                }
            ],
            icon: <IconFolders size={16} />
        },
    ],
}

export const Sidebar = ({ isOpen, setIsOpen }: { isOpen: boolean, setIsOpen: (open: boolean) => void }) => {
    return (
        <>
            <AnimatePresence mode="wait">
                {isOpen && (
                    <motion.aside
                        initial={{ x: 0 }}
                        animate={{ x: 0 }}
                        exit={{ x: -100 }}
                        transition={{ duration: 0.01, ease: "easeInOut" }}
                        className={cn(
                            "[grid-sidebar] h-screen absolute top-0  lg:sticky lg:top-0 lg:pt-4 z-30 hidden shrink-0 md:block dark:bg-[#121212] bg-neutral-200/50 border-r-1 w-[var(--fd-sidebar-width)]")}
                    >
                        <ScrollArea>
                            <DocsSidebarNav items={docsConfig.sidebarNav} setIsOpen={setIsOpen} />
                        </ScrollArea>
                    </motion.aside>
                )}
            </AnimatePresence>

            {!isOpen && (
                <div data-sidebar-placeholder className="absolute left-4 top-4 shadow-lg transition-opacity rounded-xl p-0.5 border dark:border-neutral-800 bg-white dark:bg-neutral-900 z-50 lg:block hidden">
                    <button
                        type="button"
                        aria-label="Expand Sidebar"
                        onClick={() => setIsOpen(true)}
                        className="inline-flex items-center justify-center text-sm font-medium transition-colors duration-100 disabled:pointer-events-none disabled:opacity-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-fd-ring p-2 rounded-sm cursor-pointer"
                    >
                        <PanelRightClose size={16} className="text-neutral-400" />
                    </button>
                </div>
            )}
        </>
    )
}

interface NavSection {
    title: string
    items: NavItem[]
}

interface NavItemProps {
    item: NavItem,
    pathname: string,
    className?: string
}

interface DocsSidebarNavProps {
    items: NavSection[]
    className?: string
    setIsOpen: (open: boolean) => void
}

export function DocsSidebarNav({ items, className, setIsOpen }: DocsSidebarNavProps) {
    const { pathname } = useLocation();
    return items.length ? (
        <div className={cn("w-full h-full min-h-screen text-[#1e1e1e] relative", "pt-0 py-4 px-1", className)}>
            <div className="w-full h-full px-4">
                <header className="w-full flex items-center justify-between mb-4">
                    <div className="w-full h-full flex items-center gap-2">
                        <Link to="/" className="flex items-center gap-2">
                            <IconStarSparkle size={18} style={{
                                '--nc-gradient-1-color-1': '#b95959ff',
                                '--nc-gradient-2-color-2': "pink",
                            } as React.CSSProperties}
                                className="mb-1"
                            />
                            <span className="font-semibold text-lg uppercase tracking-tight dark:text-white text-black">Opsdocs</span>
                        </Link>
                    </div>
                    <PanelLeftClose
                        onClick={() => setIsOpen(false)}
                        size={16}
                        className="cursor-pointer text-neutral-500 hover:text-foreground transition-colors"
                    />
                </header>
                <div className="space-y-4">
                    {items.map((section, index) => (
                        <div key={index} className="space-y-1.5">
                            <h4 className="text-sm font-semibold uppercase tracking-tight dark:text-neutral-200">
                                {section.title}
                            </h4>
                            <DocsSidebarNavItems items={section.items} pathname={pathname} />
                        </div>
                    ))}
                </div>
            </div>
        </div>
    ) : null
}


export function DocsSidebarNavItems({
    items,
    pathname,
}: { items: NavItem[], pathname: string }) {
    return items?.length ? (
        <div className="grid grid-flow-row auto-rows-max text-xs font-medium ml-2">
            {items.map((item, index) => (
                <NavItem key={index} item={item} pathname={pathname} />
            ))}
        </div>
    ) : null
}


function NavItem({ item, pathname, className }: NavItemProps) {
    const isActive = pathname === item.href
    const hasChildren = item.items && item.items.length > 0

    if (hasChildren) {
        return (
            <div>
                <span className={`flex w-full cursor-default items-center rounded-md text-md text-neutral-200 font-medium `}>
                    {item.title}
                </span>
                <div className={`ml-3 border-l border-border pl-3 text-xs ${isActive ? "text-white" : "light:text-[#1e1e1e]"}`}>
                    <DocsSidebarNavItems items={item.items!} pathname={pathname} />
                </div>
            </div>
        )
    }

    if (item.href && !item.disabled) {
        return (
            <Link
                to={item.href}
                className={cn(
                    "group flex w-full items-center rounded-md border border-transparent px-2 py-1",
                    item.disabled && "cursor-not-allowed opacity-60",
                    isActive ? "font-medium dark:text-white text-neutral-900" : "text-zinc-500",
                    className
                )}
                target={item.external ? "_blank" : ""}
                rel={item.external ? "noreferrer" : ""}
            >
                <p className=" hover:underline ">{item.title}</p>
                {item.label === "new" && (
                    <span className="ml-2 rounded-md border border-black bg-[#adfa1d] px-1.5 py-0.5 text-xs leading-none text-[#000000] no-underline group-hover:no-underline">
                        {item.label}
                    </span>
                )}
                {item.label === "recent" && (
                    <span className="ml-2 rounded-md border border-black  px-1.5 py-0.5 text-xs leading-none text-[#000000] no-underline group-hover:no-underline">
                        {item.label}
                    </span>
                )}
                {item.label === "updated" && (
                    <span className="ml-2 rounded-md border border-black bg-pink-400 px-1.5 py-0.5 text-xs leading-none text-[#000000] no-underline group-hover:no-underline">
                        {item.label}
                    </span>
                )}
            </Link>
        )
    }

    return (
        <span
            className={cn(
                "flex w-full cursor-not-allowed items-center rounded-md p-2 text-muted-foreground hover:underline",
                item.disabled && "cursor-not-allowed opacity-60"
            )}
        >
            {item.title}
            {item.label && (
                <span className="ml-2 rounded-md bg-muted px-1.5 py-0.5 text-xs leading-none text-muted-foreground no-underline group-hover:no-underline">
                    {item.label}
                </span>
            )}
        </span>
    )
}

import React from 'react'

interface SkeletonProps {
  variant?: "text" | "rectangular" | "circular",
  width?: string | number,
  height?: string | number,
  className?: string
}

const Skeleton = ({
  variant = "text",
  width = '100%',
  height = '16px',
  className = ''
}: SkeletonProps) => {
  const baseStyles = 'bg-gradient-to-r from-gray-200 via-gray-100 to-gray-200 bg-[length:200%_100%] animate-pulse'

  const variantStyles = {
    text: 'rounded',
    rectangular: 'rounded-md',
    circular: 'rounded-full',
  }

  const selectedVariant = variantStyles[variant] || variantStyles.text

  const circularHeight = variant === 'circular' ? width : height

  return (
    <div
      className={`${baseStyles} ${selectedVariant} ${className}`}
      style={{
        width: typeof width === 'number' ? `${width}px` : width,
        height: typeof circularHeight === 'number' ? `${circularHeight}px` : circularHeight,
      }}
    />
  )
}

export default Skeleton

import React from "react"
import { ArrowDown, ArrowUp, ArrowUpFromLine, ChevronDown, ChevronRight } from "lucide-react";
import { cn } from "@/lib/utils";
import { Link } from "react-router-dom";
import Skeleton from "./Skeleton";
import { TableProps } from "../../../types/Table";
// import {
//     IconButton,
//     Tooltip
// } from "@mui/material";

export default function Table({
    columns = [],
    data = [],
    isLoading = false,
    actions = [],
    sortConfig = { key: null, direction: null },
    onSort,
    emptyState,
    onRowClick,
    className,
    expandable = false,
    renderExpandedContent,
    rowKey = (row, index) => row.id || index
}: TableProps) {
    const [expandedRows, setExpandedRows] = React.useState(new Set());

    const toggleRow = (key: string | number, e: React.MouseEvent) => {
        e.stopPropagation();
        const newExpandedRows = new Set(expandedRows);
        if (newExpandedRows.has(key)) {
            newExpandedRows.delete(key);
        } else {
            newExpandedRows.add(key);
        }
        setExpandedRows(newExpandedRows);
    };

    const handleSort = (key: string) => {
        if (onSort) {
            onSort(key);
        }
    };



    return (
        <div className={cn("w-full overflow-hidden rounded-xl glass border-none shadow-sm", className)}>
            <div className="w-full overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-neutral-200 bg-neutral-50">
                            {expandable && (
                                <th className="px-4 py-3 w-8" />
                            )}
                            {columns.map((col) => (
                                <th
                                    key={col.key}
                                    className={cn(
                                        "px-4 py-3 text-xs font-semibold text-slate-600 uppercase tracking-wider select-none",
                                        col.className
                                    )}
                                    align={col.align || "left"}
                                >
                                    <div
                                        className={cn(
                                            "flex items-center gap-1",
                                            col.sortable && "cursor-pointer hover:text-blue-600 transition-colors",
                                            col.align === 'right' && "justify-end",
                                            col.align === 'center' && "justify-center"
                                        )}
                                        onClick={() => col.sortable && handleSort(col.key)}
                                    >
                                        {col.label}
                                        {col.sortable && (
                                            <span className="flex items-center opacity-70">
                                                {sortConfig.key === col.key ? (
                                                    sortConfig.direction === "asc" ? (
                                                        <ArrowUp size={14} className="text-blue-600 ml-1" />
                                                    ) : (
                                                        <ArrowDown size={14} className="text-blue-600 ml-1" />
                                                    )
                                                ) : (
                                                    <div className="w-3.5 h-3.5 ml-1" />
                                                )}
                                            </span>
                                        )}
                                    </div>
                                </th>
                            ))}
                            {actions.length > 0 && (
                                <th className="px-4 py-3 text-xs font-semibold text-slate-600 uppercase tracking-wider text-right w-[1%] whitespace-nowrap">
                                    Actions
                                </th>
                            )}
                        </tr>
                    </thead>

                    <tbody className="divide-y divide-white/10 bg-white">
                        {isLoading ? (
                            [...Array(5)].map((_, index) => (
                                <tr key={`skeleton-${index}`} className="animate-pulse">
                                    {columns.map((col, colIndex) => (
                                        <td key={colIndex} className="px-4 py-4">
                                            <Skeleton variant="text" width="80%" height={20} className="bg-white/50" />
                                        </td>
                                    ))}
                                    {actions.length > 0 && (
                                        <td className="px-4 py-4 text-right">
                                            <Skeleton variant="rectangular" width={60} height={24} className="rounded ml-auto bg-white/50" />
                                        </td>
                                    )}
                                </tr>
                            ))
                        ) : data.length > 0 ? (
                            data.map((row, rowIndex) => {
                                const key = rowKey(row, rowIndex);
                                const isExpanded = expandedRows.has(key);

                                return (
                                    <React.Fragment key={key}>
                                        <tr
                                            onClick={() => onRowClick && onRowClick(row)}
                                            className={cn(
                                                "transition-colors duration-200 group hover:bg-white/30",
                                                onRowClick && "cursor-pointer",
                                                isExpanded && "bg-white/20"
                                            )}
                                        >
                                            {expandable && (
                                                <td className="px-4 py-3 w-8">
                                                    {/* <IconButton
                                                        size="small"
                                                        onClick={(e: React.MouseEvent) => toggleRow(key, e)}
                                                        className="p-1 hover:bg-white/50"
                                                    >
                                                        {isExpanded ? (
                                                            <ChevronDown size={16} className="text-slate-600" />
                                                        ) : (
                                                            <ChevronRight size={16} className="text-slate-600" />
                                                        )}
                                                    </IconButton> */}
                                                </td>
                                            )}
                                            {columns.map((col) => {
                                                const cellValue = row[col.key];
                                                let displayValue = cellValue;


                                                if (col.key === 'created_at' && cellValue) {
                                                    displayValue = cellValue.length > 10 ? cellValue.slice(0, 4) : cellValue;
                                                }

                                                if (col.render) {
                                                    displayValue = col.render(cellValue, row);
                                                }

                                                if (col.key === 'provider' && cellValue) {
                                                    const val = String(cellValue).toLowerCase();
                                                    if (val.includes('eks') || val.includes('aws')) {
                                                        displayValue = (
                                                            <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-orange-100 text-orange-800 border border-orange-200">
                                                                AWS
                                                            </span>
                                                        );
                                                    } else if (val.includes('azure')) {
                                                        displayValue = (
                                                            <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-blue-100 text-blue-800 border border-blue-200">
                                                                Azure
                                                            </span>
                                                        );
                                                    } else {
                                                        displayValue = (
                                                            <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-slate-100 text-slate-800 border border-slate-200">
                                                                {cellValue}
                                                            </span>
                                                        );
                                                    }
                                                }

                                                if (displayValue === undefined || displayValue === null || displayValue === "") {
                                                    displayValue = "-";
                                                }

                                                return (
                                                    <td
                                                        key={col.key}
                                                        className={cn("px-4 py-3 text-sm text-slate-700", col.cellClassName)}
                                                        align={col.align || "left"}
                                                    >
                                                        {displayValue}
                                                    </td>
                                                );
                                            })}
                                            {actions.length > 0 && (
                                                <td className="px-4 py-2 text-right">
                                                    <div className="flex items-center justify-end gap-1 opacity-80 group-hover:opacity-100 transition-opacity">
                                                        {actions.map((action, actionIndex) => {
                                                            const isDisabled = action.disabled ? action.disabled(row) : false;
                                                            const ActionIcon = action.icon;
                                                            const linkPath = typeof action.link === 'function' ? action.link(row) : action.link;
                                                            const tooltipTitle = typeof action.tooltip === 'function' ? action.tooltip(row) : (action.tooltip || action.label || '');

                                                            const ButtonContent = (
                                                                // <IconButton
                                                                //     size="small"
                                                                //     onClick={(e: React.MouseEvent) => {
                                                                //         e.stopPropagation();
                                                                //         action.onClick?.(row);
                                                                //     }}
                                                                //     disabled={isDisabled}
                                                                //     className={cn(
                                                                //         "p-1.5 transition-all duration-200 hover:bg-white/60",
                                                                //         isDisabled && "opacity-40 cursor-not-allowed",
                                                                //         action.color === "error" && !isDisabled && "text-red-500 hover:text-red-700 hover:bg-red-50",
                                                                //         action.color === "success" && !isDisabled && "text-green-600 hover:text-green-800 hover:bg-green-50",
                                                                //         (!action.color || action.color === "default") && !isDisabled && "text-slate-600 hover:text-blue-600 hover:bg-blue-50"
                                                                //     )}
                                                                // >
                                                                //     {ActionIcon ? <ActionIcon size={16} /> : <ArrowUpFromLine size={16} />}
                                                                // </IconButton>
                                                                <></>
                                                            )

                                                            return (
                                                                <>
                                                                    {/* <Tooltip key={actionIndex} title={tooltipTitle} arrow>
                                                                        {linkPath ? (
                                                                            <Link to={linkPath} onClick={(e) => e.stopPropagation()}>
                                                                                {ButtonContent}
                                                                            </Link>
                                                                        ) : (
                                                                            <span>{ButtonContent}</span>
                                                                        )}
                                                                    </Tooltip> */}
                                                                </>
                                                            );
                                                        })}
                                                    </div>
                                                </td>
                                            )}
                                        </tr>
                                        {isExpanded && renderExpandedContent && (
                                            <tr>
                                                <td
                                                    colSpan={columns.length + (actions.length > 0 ? 1 : 0) + (expandable ? 1 : 0)}
                                                    className="px-8 py-4 bg-slate-50/50 border-y border-slate-100"
                                                >
                                                    {renderExpandedContent(row)}
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                );
                            })
                        ) : (

                            emptyState && (
                                <tr>
                                    <td
                                        colSpan={columns.length + (actions.length > 0 ? 1 : 0) + (expandable ? 1 : 0)}
                                        className="h-32 text-center text-slate-500"
                                    >
                                        {emptyState}
                                    </td>
                                </tr>
                            )

                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

import React from "react"
import { Moon, Sun } from "lucide-react"
import { motion, AnimatePresence } from "framer-motion"
import { useTheme } from "../theme-provider"
import { cn } from "@/lib/utils"

export const Toggle = () => {
    const { theme, setTheme } = useTheme()

    const toggleTheme = () => {
        setTheme(theme === "dark" ? "light" : "dark")
    }

    return (
        <button
            onClick={toggleTheme}
            className={cn(
                "relative flex items-center justify-center rounded-md transition-all duration-300 py-1.5 px-4 ring-[.5px] ring-black/20",
                "overflow-hidden flex justify-between cursor-pointer relative items-center p-2 dark:ring-[.5px] dark:ring-white/30 hover:ring-white/10 hover:scale-[.98] flex justify-center items-center dark:bg-[var(--bg)] bg-neutral-200 shadow-sm dark:shadow-[var(--shadow-s)] rounded-md outline-0 text-sm gap-2 items-center flex duration-600 ease-inOut ",
                "outline-none focus-visible:ring-primary/50"
            )}
            aria-label="Toggle theme"
        >
            <AnimatePresence mode="wait" initial={false}>
                {theme === "dark" ? (
                    <motion.div
                        key="moon"
                        initial={{ y: 20, opacity: 0, rotate: 45 }}
                        animate={{ y: 0, opacity: 1, rotate: 0 }}
                        exit={{ y: -20, opacity: 0, rotate: -45 }}
                        transition={{ duration: 0.2, ease: "easeInOut" }}
                    >
                        <Moon size={16} className="text-neutral-400 group-hover:text-neutral-200" />
                    </motion.div>
                ) : (
                    <motion.div
                        key="sun"
                        initial={{ y: 20, opacity: 0, rotate: 45 }}
                        animate={{ y: 0, opacity: 1, rotate: 0 }}
                        exit={{ y: -20, opacity: 0, rotate: -45 }}
                        transition={{ duration: 0.2, ease: "easeInOut" }}
                    >
                        <Sun size={16} className="text-yellow-500" />
                    </motion.div>
                )}
            </AnimatePresence>
            <span className="sr-only">Toggle theme</span>
        </button>
    )
}

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const alertVariants = cva(
  "relative w-full rounded-lg border px-4 py-3 text-sm [&>svg+div]:translate-y-[-3px] [&>svg]:absolute [&>svg]:left-4 [&>svg]:top-4 [&>svg]:text-foreground [&>svg~*]:pl-7",
  {
    variants: {
      variant: {
        default: "bg-background text-foreground",
        destructive:
          "border-destructive/50 text-destructive dark:border-destructive [&>svg]:text-destructive",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

const Alert = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & VariantProps<typeof alertVariants>
>(({ className, variant, ...props }, ref) => (
  <div
    ref={ref}
    role="alert"
    className={cn(alertVariants({ variant }), className)}
    {...props}
  />
))
Alert.displayName = "Alert"

const AlertTitle = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLHeadingElement>
>(({ className, ...props }, ref) => (
  <h5
    ref={ref}
    className={cn("mb-1 font-medium leading-none tracking-tight", className)}
    {...props}
  />
))
AlertTitle.displayName = "AlertTitle"

const AlertDescription = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLParagraphElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("text-sm [&_p]:leading-relaxed", className)}
    {...props}
  />
))
AlertDescription.displayName = "AlertDescription"

export { Alert, AlertTitle, AlertDescription }

